```java
import java.util.*;

class Solution {
    public List<String> findMaxOccupiedPaths(String target, List<String> files, List<Integer> sizes) {
        // 核心：同 Python，用「相等或 target+'/' 真前缀」判断 target 是否在文件系统中出现
        boolean exists = false;
        for (String p : files) {
            if (p.equals(target)
                    || (p.length() > target.length()
                        && p.startsWith(target)
                        && p.charAt(target.length()) == '/')) {
                exists = true;
                break;
            }
        }
        if (!exists) {
            return new ArrayList<>();
        }
        // 核心：每个一级子项路径 -> 其下所有文件 size 之和（Long 防累加溢出）
        Map<String, Long> agg = new HashMap<>();
        for (int i = 0; i < files.size(); i++) {
            String p = files.get(i);
            if (p.equals(target)) {
                continue;
            }
            // 关键：必须同时满足 startsWith 与下一字符为 '/'，避免 "/dir" 与 "/dir1" 串前缀误判
            if (p.length() <= target.length()
                    || !p.startsWith(target)
                    || p.charAt(target.length()) != '/') {
                continue;
            }
            String rel = p.substring(target.length() + 1);
            int slash = rel.indexOf('/');
            String child;
            if (slash < 0) {
                child = p;
            } else {
                child = target + "/" + rel.substring(0, slash);
            }
            long sz = sizes.get(i).longValue();
            agg.merge(child, sz, Long::sum);
        }
        if (agg.isEmpty()) {
            return new ArrayList<>();
        }
        // 关键：先求最大占用，再收集所有等于最大的路径
        long mx = 0;
        for (long v : agg.values()) {
            mx = Math.max(mx, v);
        }
        List<String> ans = new ArrayList<>();
        for (Map.Entry<String, Long> e : agg.entrySet()) {
            if (e.getValue() == mx) {
                ans.add(e.getKey());
            }
        }
        Collections.sort(ans);  // 题意：并列最大时字典序
        return ans;
    }
}
