var findMaxOccupiedPaths = function(target, files, sizes) {
    // 核心：判断 target 是否在文件系统中出现
    var exists = false;
    var tlen = target.length;
    for (var i = 0; i < files.length; i++) {
        var p = files[i];
        if (p === target ||
            (p.length > tlen && p.charCodeAt(tlen) === 47 /* '/' */ &&
             p.lastIndexOf(target, 0) === 0)) {
            exists = true;
            break;
        }
    }
    if (!exists) return [];

    // 核心：一级子项 -> 该子项下所有文件大小之和
    var agg = Object.create(null);
    for (var i = 0; i < files.length; i++) {
        var p = files[i];
        if (p === target) continue;
        if (p.length <= tlen || p.charCodeAt(tlen) !== 47 /* '/' */ ||
            p.lastIndexOf(target, 0) !== 0) continue;

        var rel = p.substring(tlen + 1);
        var slash = rel.indexOf('/');
        var child;
        if (slash < 0) {
            child = p;
        } else {
            child = p.substring(0, tlen + 1 + slash);
        }
        agg[child] = (agg[child] || 0) + sizes[i];
    }

    var keys = Object.keys(agg);
    if (keys.length === 0) return [];

    // 关键：全局最大占用，再筛出所有等于最大的键
    var mx = 0;
    for (var j = 0; j < keys.length; j++) {
        if (agg[keys[j]] > mx) mx = agg[keys[j]];
    }
    var ans = [];
    for (var k = 0; k < keys.length; k++) {
        if (agg[keys[k]] === mx) ans.push(keys[k]);
    }
    ans.sort();  // 题意：并列时按路径字典序升序
    return ans;
};
